class Qwen2_5_VLTextModel_with_Spatial_Tokens(Qwen2_5_VLPreTrainedModel):
    config_class = Qwen2_5_VL_VQ_SAM2Config

    def __init__(self, config: Qwen2_5_VL_VQ_SAM2Config):
        super().__init__(config)
        text_config = config.text_config
        self.text_config = text_config
        num_codebooks = 1 if config.shared_codebook else config.codebook_depth
        num_spatial_tokens = config.codebook_size * num_codebooks + 2 # +2 for the start and end tokens
        self.padding_idx = text_config.pad_token_id
        self.vocab_size = text_config.vocab_size + num_spatial_tokens

        self.embed_tokens = nn.Embedding(text_config.vocab_size + num_spatial_tokens, text_config.hidden_size, self.padding_idx)
        self.layers = nn.ModuleList(
            [Qwen2_5_VLDecoderLayer(text_config, layer_idx) for layer_idx in range(text_config.num_hidden_layers)]
        )
        self._attn_implementation = text_config._attn_implementation
        self.norm = Qwen2RMSNorm(text_config.hidden_size, eps=text_config.rms_norm_eps)
        self.rotary_emb = Qwen2_5_VLRotaryEmbedding(config=text_config)
        self.has_sliding_layers = "sliding_attention" in self.text_config.layer_types

        self.gradient_checkpointing = False
        # Initialize weights and apply final processing
        self.post_init()

    def get_input_embeddings(self):
        return self.embed_tokens

    def set_input_embeddings(self, value):
        self.embed_tokens = value

